def gen(rng, size):
    n = max(1, size)
    chars = []
    cur = rng.choice('01')
    while len(chars) < n:
        run = rng.randrange(1, 6)
        for _ in range(run):
            if len(chars) >= n:
                break
            chars.append(cur)
        cur = '1' if cur == '0' else '0'
    return [''.join(chars)]

