class Solution:
    def countBinarySubstrings(self, s):
        groups = []
        i = 0
        n = len(s)
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            groups.append(j - i)
            i = j
        total = 0
        for a in range(1, len(groups)):
            total += min(groups[a - 1], groups[a])
        return total

