var countBinarySubstrings = function(s) {
    let prev = 0, cur = 1, total = 0;
    for (let i = 1; i < s.length; i++) {
        if (s[i] === s[i - 1]) {
            cur++;
        } else {
            total += Math.min(prev, cur);
            prev = cur;
            cur = 1;
        }
    }
    total += Math.min(prev, cur);
    return total;
